  {
   "cell_type": "markdown",
   "id": "fa756fd0-1708-4ae6-be53-3cd17754aa9a",
   "metadata": {},
   "source": [
    "# **Step 4: Model Training & Evaluation**"
   ]
  },
  {
   "cell_type": "markdown",
   "id": "50b80f13-5b77-4ca9-a06f-dde1a3df542b",
   "metadata": {},
   "source": [
    "# **Import Machine Learning Models**"
   ]
  },
  {
   "cell_type": "code",
   "execution_count": 71,
   "id": "203e6156-fba0-4e76-9d61-4b16725dea4b",
   "metadata": {},
   "outputs": [],
   "source": [
    "# ==========================\n",
    "# Import Machine Learning Models\n",
    "# ==========================\n",
    "\n",
    "from sklearn.linear_model import LinearRegression\n",
    "from sklearn.linear_model import Ridge\n",
    "from sklearn.linear_model import Lasso\n",
    "\n",
    "from sklearn.tree import DecisionTreeRegressor\n",
    "\n",
    "from sklearn.ensemble import RandomForestRegressor\n",
    "from sklearn.ensemble import GradientBoostingRegressor"
   ]
  },
  {
   "cell_type": "markdown",
   "id": "e23500b3-a2b5-405e-9ca2-b99c28ded5ba",
   "metadata": {},
   "source": [
    "# **Import Evaluation Metrics**"
   ]
  },
  {
   "cell_type": "code",
   "execution_count": 72,
   "id": "1382af33-c53a-4262-87c4-e1ba7b6ccc5a",
   "metadata": {},
   "outputs": [],
   "source": [
    "# ==========================\n",
    "# Import Evaluation Metrics\n",
    "# ==========================\n",
    "\n",
    "from sklearn.metrics import (\n",
    "    mean_absolute_error,\n",
    "    mean_squared_error,\n",
    "    r2_score\n",
    ")"
   ]
  },
  {
   "cell_type": "markdown",
   "id": "3607459c-45c2-461f-a5ed-b3dc65c78ca6",
   "metadata": {},
   "source": [
    "# **Create Models Dictionary**"
   ]
  },
  {
   "cell_type": "code",
   "execution_count": 73,
   "id": "7726dec8-c0a4-4f86-b93a-752f471d9362",
   "metadata": {},
   "outputs": [],
   "source": [
    "# ==========================\n",
    "# Create Models\n",
    "# ==========================\n",
    "\n",
    "models = {\n",
    "\n",
    "    \"Linear Regression\": LinearRegression(),\n",
    "\n",
    "    \"Ridge Regression\": Ridge(),\n",
    "\n",
    "    \"Lasso Regression\": Lasso(),\n",
    "\n",
    "    \"Decision Tree\": DecisionTreeRegressor(random_state=42),\n",
    "\n",
    "    \"Random Forest\": RandomForestRegressor(\n",
    "        n_estimators=200,\n",
    "        random_state=42\n",
    "    ),\n",
    "\n",
    "    \"Gradient Boosting\": GradientBoostingRegressor(\n",
    "        random_state=42\n",
    "    )\n",
    "\n",
    "}"
   ]
  },
  {
   "cell_type": "markdown",
   "id": "b4780dda-11bb-453d-bca8-4b807d38750e",
   "metadata": {},
   "source": [
    "# **Train and Evaluate All Models**"
   ]
  },
  {
   "cell_type": "code",
   "execution_count": 74,
   "id": "cb583eac-ad97-47bf-a667-1cf0c52a3d9a",
   "metadata": {},
   "outputs": [],
   "source": [
    "# ==========================\n",
    "# Train and Evaluate Models\n",
    "# ==========================\n",
    "\n",
    "results = []\n",
    "\n",
    "for name, model in models.items():\n",
    "\n",
    "    # Train\n",
    "    model.fit(X_train, y_train)\n",
    "\n",
    "    # Prediction\n",
    "    y_pred = model.predict(X_test)\n",
    "\n",
    "    # Metrics\n",
    "    mae = mean_absolute_error(y_test, y_pred)\n",
    "\n",
    "    mse = mean_squared_error(y_test, y_pred)\n",
    "\n",
    "    rmse = np.sqrt(mse)\n",
    "\n",
    "    r2 = r2_score(y_test, y_pred)\n",
    "\n",
    "    results.append([\n",
    "        name,\n",
    "        mae,\n",
    "        rmse,\n",
    "        r2\n",
    "    ])"
   ]
  },
